mapper.select:
SELECT follower_user_id, following_user_id, status, created_at, updated_at, deleted_at
FROM social.user_follows
WHERE follower_user_id = #{followerId} AND following_user_id = #{followingId}

mapper.update:
UPDATE social.user_follows SET status = 'ACTIVE', updated_at = #{now}, deleted_at = NULL
WHERE follower_user_id = #{followerId} AND following_user_id = #{followingId}
  AND status = 'PENDING' AND deleted_at IS NULL

UPDATE social.user_follows SET status = 'DELETED', updated_at = #{now}, deleted_at = #{now}
WHERE follower_user_id = #{followerId} AND following_user_id = #{followingId}
  AND status != 'DELETED' AND deleted_at IS NULL
  AND status = #{requiredStatus}
